    const array DAY_STRINGS = [1 => '01', 2 => '02', 3 => '03', 4 => '04', 5 => '05', 6 => '06', 7 => '07', 8 => '08', 9 => '09', 10 => '10', 11 => '11', 12 => '12', 13 => '13', 14 => '14', 15 => '15', 16 => '16', 17 => '17', 18 => '18', 19 => '19', 20 => '20', 21 => '21', 22 => '22', 23 => '23', 24 => '24', 25 => '25', 26 => '26', 27 => '27', 28 => '28', 29 => '29', 30 => '30', 31 => '31'];

    /**
     * @throws \DateMalformedStringException
     */
    public function parse(string $inputPath, string $outputPath): void
    {
        gc_disable();

        // pre-compute dates
        $dateIds = [];
        $dates = [];
        $dateCount = 0;
        for ($y = 21; $y <= 26; $y++) {
            $ymStr = "{$y}-01-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-02-";
            $maxD = $y === 24 ? 29 : 28;
            for ($d = 1; $d <= $maxD; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-03-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-04-";
            for ($d = 1; $d <= 30; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-05-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-06-";
            for ($d = 1; $d <= 30; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-07-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-08-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-09-";
            for ($d = 1; $d <= 30; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-10-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-11-";
            for ($d = 1; $d <= 30; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }

            $ymStr = "{$y}-12-";
            for ($d = 1; $d <= 31; $d++) {
                $dStr = self::DAY_STRINGS[$d];
                $dateIds["{$ymStr}{$dStr}"] = $dateCount;
                $dates[$dateCount] = "20{$ymStr}{$dStr}";
                $dateCount++;
            }
        }

        $pathCount = 0;
        $outputData = [];

        $input = fopen($inputPath, 'r');
        stream_set_read_buffer($input, self::FILE_READ_SIZE);

        $carry = '';
        while (($chunk = fread($input, self::FILE_READ_SIZE)) !== '') {
            $buffer = $carry . $chunk;
            $position = 0;

            while (($lineEnd = strpos($buffer, PHP_EOL, $position)) !== false) {
                $lineLength = $lineEnd - $position;

                $path = substr($buffer, $position + 25, $lineLength - 51);
                $date = substr($buffer, $lineEnd - 23, 8);
                $dateId = $dateIds[$date];

                if (isset($outputData[$path])) {
                    $outputData[$path][$dateId]++;
                } else {
                    $pathCounts = self::INITIAL_COUNTS;
                    $pathCounts[$dateId] = 1;
                    $outputData[$path] = $pathCounts;
                    $pathCount++;
                }
                $position = $lineEnd + 1;
            }

            $carry = substr($buffer, $position);
        }

        if ($carry !== '') {
            $lineLength = strlen($carry);
            $path = substr($carry, 25, $lineLength - 51);
            $date = substr($carry, $lineLength - 23, 8);
            $dateId = $dateIds[$date] ?? null;
            if ($dateId !== null) {
                if (isset($outputData[$path])) {
                    $outputData[$path][$dateId]++;
                } else {
                    $pathCounts = self::INITIAL_COUNTS;
                    $pathCounts[$dateId] = 1;
                    $outputData[$path] = $pathCounts;
                    $pathCount++;
                }
            }
        }

        $outputJson = "{" . PHP_EOL;

        $totalPathsCount = $pathCount;
        $pathIndex = 0;
        foreach ($outputData as $path => $pathCounts) {
            $outputJson .= "    \"\/blog\/$path\": {" . PHP_EOL;

            $firstDate = true;
            for ($dateId = 0; $dateId < $dateCount; $dateId++) {
                $count = $pathCounts[$dateId];
                if ($count === 0) {
                    continue;
                }

                if (!$firstDate) {
                    $outputJson .= "," . PHP_EOL;
                }
                $date = $dates[$dateId];
                $outputJson .= "        \"$date\": $count";
                $firstDate = false;
            }

            $outputJson .= PHP_EOL;
            $outputJson .= "    }";
            if ($pathIndex < $totalPathsCount - 1) {
                $outputJson .= ",";
            }
            $outputJson .= PHP_EOL;

            $pathIndex++;
        }

        $outputJson .= "}";

        file_put_contents($outputPath, $outputJson);
    }
}
